pageProps.query:
    query contentQuery($relativePath: String!) {
  ...LayoutQueryFragment
  page(relativePath: $relativePath) {
    ...PageParts
  }
}

    fragment LayoutQueryFragment on Query {
  global(relativePath: "index.json") {
    ...GlobalParts
  }
}

    fragment GlobalParts on Global {
  header {
    __typename
    icon
    color
    nav {
      __typename
      href
      label
    }
  }
  theme {
    __typename
    color
    font
    icon
    darkMode
  }
}


    fragment PageParts on Page {
  title
  blocks {
    __typename
    ... on PageBlocksBroughtToYouBy {
      largeText
    }
    ... on PageBlocksHero {
      heading
      subtitle
      imageLeft {
        __typename
        src
        alt
      }
      iconLeft {
        __typename
        src
        alt
      }
      imageRight {
        __typename
        src
        alt
      }
      iconRight {
        __typename
        src
        alt
      }
      color
    }
    ... on PageBlocksEventTicket {
      heading
    }
    ... on PageBlocksHr {
      icon
    }
    ... on PageBlocksHowItWorks {
      heading
      items {
        __typename
        icon
        title
        text
      }
    }
    ... on PageBlocksContent {
      body
    }
    ... on PageBlocksTestimonials {
      heading
      logos {
        __typename
        src
        alt
        width
        height
      }
      quotes {
        __typename
        quote
        author
        jobTitle
      }
    }
  }
}
